function candidate(mediaTypeLookup, extensionLookup) {
  var registry = typeof db !== 'undefined' ? db : typeof mimeDb !== 'undefined' ? mimeDb : typeof mimeDatabase !== 'undefined' ? mimeDatabase : null;
  var sourceOrder = { nginx: 0, apache: 1, undefined: 2, iana: 3 };

  Object.keys(registry || {}).forEach(function (mediaType) {
    var metadata = registry[mediaType];
    var suffixes = metadata && metadata.extensions;

    if (!suffixes || suffixes.length === 0) {
      return;
    }

    mediaTypeLookup[mediaType] = suffixes;

    suffixes.forEach(function (suffix) {
      var currentType = extensionLookup[suffix];

      if (currentType) {
        var currentMetadata = registry[currentType] || {};
        var currentRank = sourceOrder[String(currentMetadata.source)];
        var nextRank = sourceOrder[String(metadata.source)];

        if (currentRank === undefined) {
          currentRank = sourceOrder.undefined;
        }
        if (nextRank === undefined) {
          nextRank = sourceOrder.undefined;
        }

        if (currentType !== 'application/octet-stream' &&
            (currentRank > nextRank ||
              (currentRank === nextRank && currentType.indexOf('application/') === 0))) {
          return;
        }
      }

      extensionLookup[suffix] = mediaType;
    });
  });
}
